code.C:
#include <stdio.h>
int main() {
    int a, b, c, d;
    scanf("%d %d %d %d", &a, &b, &c, &d);
    int maxStart = (a > c) ? a : c;
    int minEnd = (b < d) ? b : d;
    if (maxStart <= minEnd) {
        printf("%d\n", minEnd - maxStart + 1);
    } else {
        printf("0\n");
    }
    return 0;
}

