        } else {
            System.out.println(0);
        }
    }
}

code.JavaScript:
const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
rl.on('line', (input) => {
    const [a, b, c, d] = input.split(' ').map(Number);
    const maxStart = Math.max(a, c);
    const minEnd = Math.min(b, d);
    if (maxStart <= minEnd) {
        console.log(minEnd - maxStart + 1);
    } else {
        console.log(0);
    }
    rl.close();
});

